from qiskit import QuantumCircuit
from qiskit.quantum_info import Statevector
from qiskit.visualization import plot_bloch_vector, plot_bloch_multivector
import matplotlib

qc = QuantumCircuit(2)
qc.h(0)
qc.cx(0, 1)
state = Statevector.from_instruction(qc)
n_qubits = state.num_qubits

def spheres(fn):
    try:
        r = fn()
        if isinstance(r, matplotlib.figure.Figure):
            return len(r.axes)
        return f"returned {type(r).__name__}"
    except Exception as e:
        return f"raised {type(e).__name__}"

calls = {
    "A": lambda: plot_bloch_vector(state, coord_type="spherical"),
    "B": lambda: plot_bloch_vector(state.data),
    "C": lambda: plot_bloch_multivector([0, 0, 1]),
    "D": lambda: plot_bloch_multivector(state),
}
evidence = {}
proven = []
for k, fn in calls.items():
    s = spheres(fn)
    per_qubit = isinstance(s, int) and s == n_qubits
    evidence[k] = f"result: {s} Bloch-sphere axes (need {n_qubits}, one per qubit) -> correct={per_qubit}"
    if per_qubit:
        proven.append(k)

emit_verdict({
    "answer": proven,
    "evidence": evidence,
    "observed": {"num_qubits": n_qubits, "correct_calls": proven},
})
